// =============================================================
// AGGREGATOR — CxC Branches (simplified, no error handlers)
// Reads raw Anthropic responses directly from each Claude node.
// Uses CxC Splitter item index for chapter_number pairing.
// =============================================================
const settings = $('Settings').first().json;
const book_id  = settings.book_id;

function getAll(nodeName) {
  try { return $(nodeName).all().map(i => i.json); } catch(_) { return []; }
}

const cxcItems      = getAll('CxC Splitter');
const summaryResps  = getAll('Claude — chapter_summaries');
const charResps     = getAll('Claude — characters');
const dialogueResps = getAll('Claude — dialogue');
const grammarResps  = getAll('Claude — grammar');

function getText(resp) { return resp?.content?.[0]?.text ?? null; }
function isErr(resp) { const sc = resp?.statusCode; return (typeof sc === 'number' && sc >= 400) || resp?.type === 'error'; }

const all_chapter_summaries = summaryResps
  .map((resp, i) => ({ chapter_number: cxcItems[i]?.chapter_number ?? (i + 1), analysis_text: isErr(resp) ? null : getText(resp) }))
  .filter(r => r.analysis_text !== null)
  .sort((a, b) => a.chapter_number - b.chapter_number);

function extractNames(text) {
  if (!text) return [];
  try {
    const p = JSON.parse(text);
    if (Array.isArray(p.characters)) return p.characters.map(String);
    if (Array.isArray(p)) return p.map(c => (typeof c === 'string' ? c : c.name)).filter(Boolean);
  } catch (_) {}
  return [];
}

const charMap = {}; let charIdx = 0;
charResps.forEach((resp, i) => {
  if (isErr(resp)) return;
  const ch = cxcItems[i]?.chapter_number ?? (i + 1);
  for (const name of extractNames(getText(resp))) {
    const key = name.toLowerCase().trim();
    if (!charMap[key]) { charMap[key] = { character_id: `${book_id}_char_${charIdx++}`, name, chapter_appearances: [] }; }
    if (!charMap[key].chapter_appearances.includes(ch)) { charMap[key].chapter_appearances.push(ch); }
  }
});
const character_roster = Object.values(charMap).sort((a, b) => a.character_id.localeCompare(b.character_id));

const passThrough = resps => resps
  .map((resp, i) => ({ chapter_number: cxcItems[i]?.chapter_number ?? (i + 1), analysis_text: isErr(resp) ? null : getText(resp) }))
  .filter(r => r.analysis_text !== null)
  .sort((a, b) => a.chapter_number - b.chapter_number);

return [{ json: { ...settings, book_id, total_chapters: all_chapter_summaries.length, all_chapter_summaries, character_roster, dialogue_results: passThrough(dialogueResps), grammar_results: passThrough(grammarResps), aggregated_at: new Date().toISOString() } }];

// =============================================================
// PxP COMBINER (simplified, no error handlers)
// Merge append order: sentence_patterns first (0..N-1), spaCy second (N..2N-1).
// Uses $('PxP Splitter').all() for chapter_number / paragraph_index pairing.
// =============================================================
const allItems  = $input.all();
const settings  = $('Settings').first().json;
const pxpItems  = $('PxP Splitter').all().map(i => i.json);
const N         = pxpItems.length;

const sItems  = allItems.slice(0, N).map(i => i.json);   // sentence_patterns responses
const spItems = allItems.slice(N).map(i => i.json);      // spaCy responses

function isErr(r) { const sc = r?.statusCode; return typeof sc === 'number' && sc >= 400; }

return pxpItems.map((pxp, i) => ({
  json: {
    book_id:                    settings.book_id,
    granularity:                'paragraph',
    chapter_number:             pxp.chapter_number,
    paragraph_index:            pxp.paragraph_index,
    sentence_patterns_analysis: isErr(sItems[i]) ? null : (
  typeof sItems[i]?.output === 'string' ? sItems[i].output : JSON.stringify(sItems[i]?.output ?? null)
),
    sentence_patterns_error:    isErr(sItems[i])  ? `HTTP ${sItems[i].statusCode}` : null,
    spacy_analysis:             isErr(spItems[i]) ? null : (spItems[i] ?? null),
    spacy_error:                isErr(spItems[i]) ? `HTTP ${spItems[i].statusCode}` : null,
  }
})).sort((a, b) => {
  const cd = a.chapter_number - b.chapter_number;
  return cd !== 0 ? cd : a.paragraph_index - b.paragraph_index;
});

const item     = $input.first();
const settings = $('Settings').first().json;
const NS       = 'narrative_arc';
const book_id  = settings.book_id;

const output = item.json?.output ?? {};
const text   = typeof output === 'string' ? output : JSON.stringify(output);

if (!text || text.trim().length === 0) { return []; }

return [{
  json: {
    book_id,
    namespace:       NS,
    granularity:     'full_book',
    chapter_number:  null,
    paragraph_index: null,
    chunk_index:     0,
    chunk_text:      text,
    analysis_text:   text,
    text:            text,
    ...output
  }
}];

