// CHUNKER — dialogue
// Runs once per chapter item.
// Reads content[0].text from raw Claude response.
// Uses $itemIndex to pair with CxC Splitter for chapter_number.
// =============================================================
const item     = $input.item;
const settings = $('Settings').first().json;
const NS       = 'dialogue';
const text = typeof item.json?.output === 'string'
  ? item.json.output
  : JSON.stringify(item.json?.output ?? '');

const chapter_number = $('CxC Splitter').all()[$itemIndex]?.json?.chapter_number ?? ($itemIndex + 1);
const text     = item.json?.content?.[0]?.text ?? '';

const CHUNK_SIZE    = 2000;
const CHUNK_OVERLAP = 200;

if (!text || text.trim().length === 0) { return []; }

const chunks = [];
let start = 0;
while (start < text.length) {
  const end = Math.min(start + CHUNK_SIZE, text.length);
  chunks.push(text.slice(start, end));
  if (end >= text.length) break;
  start += CHUNK_SIZE - CHUNK_OVERLAP;
}

return chunks.map((chunk_text, chunk_index) => ({
  json: {
    book_id,
    namespace:       NS,
    granularity:     'chapter',
    chapter_number,
    paragraph_index: null,
    chunk_index,
    chunk_text,
    analysis_text:   chunk_text,
  }
}));

