parameters.jsCode:
const raw = $('Settings').first().json.text
  || $input.first().json.text 
  || $input.first().json.chapter_text
  || $input.first().json.book_text
  || $input.first().json.data
  || $input.first().json.content
  || '';

let text = raw.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

// Strip Gutenberg HEADER — everything up to and including the START marker
const gutenbergStart = text.search(/\*{3}\s*START OF (THE |THIS )?PROJECT GUTENBERG/i);
if (gutenbergStart > -1) text = text.slice(text.indexOf('\n', gutenbergStart) + 1).trim();

// Strip Gutenberg FOOTER
const gutenbergEnd = text.search(
  /\*{3}\s*END OF (THE |THIS )?PROJECT GUTENBERG|\bEnd of (the )?Project Gutenberg|\bEnd of this Project Gutenberg|\bProduced by /i
);
if (gutenbergEnd > -1) text = text.slice(0, gutenbergEnd).trim();

const settings = $('Settings').first().json;

const BLOCKLIST = /gutenberg|license|copyright|permission|distribute|trademark|donate|foundation|project pg/i;
const NAMED = /^(Chapter|CHAPTER|Stave|STAVE|Part|PART)[\t ]+(\d+|[IVXLCDM]+)|^(Preface|PREFACE|Introduction|INTRODUCTION|Prologue|PROLOGUE|Epilogue|EPILOGUE|Interlude|INTERLUDE|Foreword|FOREWORD|Afterword|AFTERWORD|Appendix|APPENDIX)/;
const TITLE_CASE = /^[A-Z][A-Za-z\u2018\u2019'\-]*(?:[ \t]+[A-Za-z\u2018\u2019'\-]+){0,6}$/;

const lines = text.split('\n');
const matches = [];

for (let i = 0; i < lines.length; i++) {
  const line = lines[i].trim();
  if (!line || BLOCKLIST.test(line)) continue;
  if (line.endsWith('.') || line.endsWith(',') || line.endsWith(';')) continue;
  const isNamed = NAMED.test(line);
  const isTitleCase = TITLE_CASE.test(line);
  if (!isNamed && !isTitleCase) continue;
  if (!isNamed && i > 0 && lines[i - 1].trim() !== '') continue;

  // Check the last non-empty line before this heading.
  // If it ends with , : or ; the "heading" is mid-paragraph context — skip it.
  let prevContent = '';
  for (let j = i - 1; j >= 0; j--) {
    const prev = lines[j].trim();
    if (prev) { prevContent = prev; break; }
  }
  if (prevContent && /[,;:]$/.test(prevContent)) continue;

  const offset = lines.slice(0, i).reduce((acc, l) => acc + l.length + 1, 0);
  matches.push({ index: offset, heading: line });
}

if (matches.length === 0) {
  return [{
    json: {
      ...settings,
      granularity: 'chapter',
      chapter_number: 1,
      chapter_heading: 'Full Text (no chapters detected)',
      chapter_text: text.trim(),
      text: text.trim(),
      word_count: text.trim().split(/\s+/).filter(Boolean).length,
      _debug_input_length: text.length,
      _debug_first_100: text.slice(0, 100)
    }
  }];
}

// Build raw sections
const sections = matches.map((match, i) => {
  const start = match.index;
  const end = i + 1 < matches.length ? matches[i + 1].index : text.length;
  const chapter_text = text.slice(start, end).trim();
  return { heading: match.heading, chapter_text, word_count: chapter_text.split(/\s+/).filter(Boolean).length };
});

// Merge sections under 50 words into the previous section
const merged = [];
for (const section of sections) {
  if (section.word_count < 300 && merged.length > 0) {
    const prev = merged[merged.length - 1];
    prev.chapter_text += '\n\n' + section.chapter_text;
    prev.word_count = prev.chapter_text.split(/\s+/).filter(Boolean).length;
  } else {
    merged.push(section);
  }
}

return merged.map((section, i) => ({
  json: {
    ...settings,
    granularity: 'chapter',
    chapter_number: i + 1,
    chapter_heading: section.heading,
    chapter_text: section.chapter_text,
    text: section.chapter_text,
    word_count: section.word_count
  }
}));

const raw = $('Settings').first().json.text
  || $input.first().json.text 
  || $input.first().json.chapter_text
  || $input.first().json.book_text
  || $input.first().json.data
  || $input.first().json.content
  || '';

let text = raw.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

// Strip Gutenberg footer
const gutenbergEnd = text.search(
  /(\*{3}\s*END OF (THE |THIS )?PROJECT GUTENBERG)|(\bEnd of (the )?Project Gutenberg)|(\bEnd of this Project Gutenberg)|(\bProduced by )|(\*\*\* START OF TH)/i
);
if (gutenbergEnd > -1) text = text.slice(0, gutenbergEnd).trim();

const settings = $('Settings').first().json;

const BLOCKLIST = /gutenberg|license|copyright|permission|distribute|trademark|donate|foundation|project pg/i;
const NAMED = /^(Chapter|CHAPTER|Part|PART)[\t ]+(\d+|[IVXLCDM]+)|^(Preface|PREFACE|Introduction|INTRODUCTION|Prologue|PROLOGUE|Epilogue|EPILOGUE|Interlude|INTERLUDE|Foreword|FOREWORD|Afterword|AFTERWORD|Appendix|APPENDIX)/;
const TITLE_CASE = /^[A-Z][A-Za-z\u2018\u2019'\-]*(?:[ \t]+[A-Za-z\u2018\u2019'\-]+){0,6}$/;

const lines = text.split('\n');
const chapterOffsets = [];

for (let i = 0; i < lines.length; i++) {
  const line = lines[i].trim();
  if (!line || BLOCKLIST.test(line)) continue;
  if (line.endsWith('.') || line.endsWith(',') || line.endsWith(';')) continue;
  const isNamed = NAMED.test(line);
  const isTitleCase = TITLE_CASE.test(line);
  if (!isNamed && !isTitleCase) continue;
  if (!isNamed && i > 0 && lines[i - 1].trim() !== '') continue;

  // Skip if previous non-empty line ends with , : or ; (mid-paragraph context)
  let prevContent = '';
  for (let j = i - 1; j >= 0; j--) {
    const prev = lines[j].trim();
    if (prev) { prevContent = prev; break; }
  }
  if (prevContent && /[,;:]$/.test(prevContent)) continue;

  const offset = lines.slice(0, i).reduce((acc, l) => acc + l.length + 1, 0);
  chapterOffsets.push({ chapter_number: chapterOffsets.length + 1, index: offset });
}

const chapters = chapterOffsets.length > 0
  ? chapterOffsets.map((ch, i) => ({
      chapter_number: ch.chapter_number,
      start: ch.index,
      end: i + 1 < chapterOffsets.length ? chapterOffsets[i + 1].index : text.length
    }))
  : [{ chapter_number: 1, start: 0, end: text.length }];

const results = [];
let realChapterNumber = 0;

for (const chapter of chapters) {
  const chapterText = text.slice(chapter.start, chapter.end);
  const paragraphs = chapterText
    .split(/\n{2,}/)
    .map(p => p.replace(/\n/g, ' ').trim())
    .filter(p => p.split(/\s+/).filter(Boolean).length >= 10);

  // Skip chapters that produce no valid paragraphs — don't increment chapter number
  if (paragraphs.length === 0) continue;
  realChapterNumber++;

  paragraphs.forEach((paragraph_text, paragraph_index) => {
    results.push({
      json: {
        ...settings,
        granularity: 'paragraph',
        chapter_number: realChapterNumber,
        paragraph_index,
        paragraph_text,
        text: paragraph_text,
        word_count: paragraph_text.split(/\s+/).filter(Boolean).length
      }
    });
  });
}
return results;

const raw = $input.first().json.text
  || $input.first().json.book_text
  || $input.first().json.data
  || $input.first().json.content
  || '';

const text = raw.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
const settings = $('Settings').first().json;

return [{
  json: {
    ...settings,
    granularity: 'full_book',
    book_text: text,
    text: text,
    char_count: text.length,
    word_count: text.split(/\s+/).filter(Boolean).length
  }
}];
